import React, { useState, useRef, useEffect } from 'react';
import { Link } from 'react-router-dom';

const VideoCard = ({ video, hoveredVideo, setHoveredVideo, formatViews, formatDuration }) => {
  const [imageError, setImageError] = useState(false);
  const isHovered = hoveredVideo === video.id;
  const videoRef = useRef(null);
  const hlsRef = useRef(null);

  // HLS 悬浮预览（抓取视频）
  useEffect(() => {
    if (!isHovered || !video.is_scraped || !video.source_url) return;

    const proxyUrl = `http://localhost:5000/api/video/proxy?url=${encodeURIComponent(video.source_url)}`;

    const init = (Hls) => {
      const el = videoRef.current;
      if (!el) return;
      if (hlsRef.current) { hlsRef.current.destroy(); hlsRef.current = null; }
      if (Hls.isSupported()) {
        const hls = new Hls({ enableWorker: true, maxBufferLength: 10 });
        hlsRef.current = hls;
        hls.loadSource(proxyUrl);
        hls.attachMedia(el);
        hls.on(Hls.Events.MANIFEST_PARSED, () => el.play().catch(() => {}));
      } else if (el.canPlayType('application/vnd.apple.mpegurl')) {
        el.src = proxyUrl;
        el.play().catch(() => {});
      }
    };

    if (window.Hls) {
      setTimeout(() => init(window.Hls), 50);
    } else {
      const s = document.createElement('script');
      s.src = 'https://cdn.jsdelivr.net/npm/hls.js@latest/dist/hls.min.js';
      s.onload = () => setTimeout(() => init(window.Hls), 50);
      document.head.appendChild(s);
    }

    return () => {
      if (hlsRef.current) { hlsRef.current.destroy(); hlsRef.current = null; }
    };
  }, [isHovered, video]);

  const renderThumbnail = () => {
    if (imageError || !video.cover_image) {
      return (
        <div className="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center">
          <svg className="w-12 h-12 text-white/50" fill="currentColor" viewBox="0 0 20 20">
            <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
          </svg>
        </div>
      );
    }
    return (
      <img
        src={video.is_scraped && video.cover_image?.startsWith('http') ? video.cover_image : `http://localhost:5000/api/video/cover/${video.id}`}
        alt={video.title}
        className="w-full h-full object-cover"
        onError={() => setImageError(true)}
      />
    );
  };

  return (
    <div
      className="group bg-white rounded-xl shadow-sm overflow-hidden hover:shadow-md transition-shadow"
      onMouseEnter={() => setHoveredVideo(video.id)}
      onMouseLeave={() => setHoveredVideo(null)}
    >
      <Link to={`/video/${video.id}`}>
        <div className="relative aspect-video overflow-hidden">
          {isHovered && video.is_scraped ? (
            <video
              ref={videoRef}
              muted
              loop
              playsInline
              className="w-full h-full object-cover"
            />
          ) : isHovered && !video.is_scraped ? (
            <video
              src={`http://localhost:5000/api/video/stream/${video.id}`}
              autoPlay muted loop
              className="w-full h-full object-cover"
            />
          ) : video.cover_image ? (
            renderThumbnail()
          ) : (
            <div className="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center">
              <svg className="w-12 h-12 text-white/50" fill="currentColor" viewBox="0 0 20 20">
                <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
              </svg>
            </div>
          )}
          {!isHovered && (
            <div className="absolute bottom-2 right-2 bg-black/70 text-white text-xs px-2 py-1 rounded">
              {formatDuration ? formatDuration(video.duration) : '00:00'}
            </div>
          )}
        </div>
      </Link>

      <div className="p-4">
        <h3 className="font-semibold text-gray-900 mb-1 line-clamp-2 group-hover:text-primary-600 transition-colors">
          {video.title}
        </h3>
        <p className="text-sm text-gray-500 mb-2">{video.author}</p>
        <div className="flex items-center text-xs text-gray-400 space-x-3">
          <span>{formatViews ? formatViews(video.view_count) : video.view_count} 次观看</span>
          <span>•</span>
          <span>{new Date(video.created_at).toLocaleDateString()}</span>
        </div>
      </div>
    </div>
  );
};

export default VideoCard;
